INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c1977ce3-5ae1-4d22-8fba-55e0bd8412db', $q$Is Umbraco free?$q$, $q$Yes, the core Umbraco CMS is free and open source under the MIT license; Umbraco Cloud managed hosting is a separate paid service.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c1977ce3-5ae1-4d22-8fba-55e0bd8412db', $q$Who created Umbraco?$q$, $q$Umbraco was created by Niels Hartvig, who began development around 2000 and open-sourced it in 2004.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c1977ce3-5ae1-4d22-8fba-55e0bd8412db', $q$What programming language is Umbraco built in?$q$, $q$Umbraco is built in C# on Microsoft's .NET (ASP.NET) framework.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c1977ce3-5ae1-4d22-8fba-55e0bd8412db', $q$Where is Umbraco headquartered?$q$, $q$Umbraco A/S is headquartered in Odense, Denmark, with a U.S. headquarters in Charlotte, North Carolina.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c1977ce3-5ae1-4d22-8fba-55e0bd8412db', $q$How much does Umbraco Cloud cost?$q$, $q$Umbraco Cloud starts around 55 dollars per month for the Starter plan, rising to around 330 for Standard, 900 for Professional, and custom pricing for Enterprise.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c1977ce3-5ae1-4d22-8fba-55e0bd8412db', $q$How many websites run on Umbraco?$q$, $q$More than 500,000 live websites run on Umbraco CMS and Umbraco Cloud.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c1977ce3-5ae1-4d22-8fba-55e0bd8412db', $q$Is Umbraco headless?$q$, $q$Umbraco supports headless and hybrid delivery through its Content Delivery API, in addition to traditional server-rendered pages.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c1977ce3-5ae1-4d22-8fba-55e0bd8412db', $q$What license does Umbraco use?$q$, $q$Umbraco has been available under the MIT open-source license since version 4.5.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c1977ce3-5ae1-4d22-8fba-55e0bd8412db', $q$Enterprise .NET websites$q$, $q$Organizations already using Microsoft's .NET stack build content-managed sites on Umbraco to fit existing infrastructure.$q$, $q$Enterprise IT and .NET development teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c1977ce3-5ae1-4d22-8fba-55e0bd8412db', $q$Custom content architectures$q$, $q$Agencies build highly custom content models for clients with specific editorial and data structure needs.$q$, $q$Digital agencies and freelance .NET developers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c1977ce3-5ae1-4d22-8fba-55e0bd8412db', $q$Headless content delivery$q$, $q$Teams use Umbraco's Content Delivery API to power decoupled front ends built in React, Vue, or other frameworks.$q$, $q$Development teams building headless/JAMstack sites$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('c1977ce3-5ae1-4d22-8fba-55e0bd8412db', $q$Umbraco CMS (self-hosted)$q$, $q$Free$q$, $q$n/a$q$, NULL, $q$["Full open-source CMS","MIT license","Self-hosted"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('c1977ce3-5ae1-4d22-8fba-55e0bd8412db', $q$Umbraco Cloud Starter$q$, $q$~$55/month$q$, $q$monthly$q$, NULL, $q$["Shared infrastructure","Up to 10 custom domains","Low-traffic sites"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('c1977ce3-5ae1-4d22-8fba-55e0bd8412db', $q$Umbraco Cloud Standard$q$, $q$~$330/month$q$, $q$monthly$q$, NULL, $q$["Higher traffic capacity","More resources than Starter"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('c1977ce3-5ae1-4d22-8fba-55e0bd8412db', $q$Umbraco Cloud Professional$q$, $q$~$900/month$q$, $q$monthly$q$, NULL, $q$["Production-grade resources","Higher SLAs"]$q$::jsonb, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('c1977ce3-5ae1-4d22-8fba-55e0bd8412db', $q$Umbraco Cloud Enterprise$q$, $q$Custom$q$, $q$annual contract$q$, NULL, $q$["Dedicated infrastructure","Custom SLAs and support"]$q$::jsonb, 4);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c1977ce3-5ae1-4d22-8fba-55e0bd8412db', $q$overview$q$, $q$What Is Umbraco$q$, 2, ARRAY[$q$Umbraco is a free, open-source content management system built on Microsoft's .NET (ASP.NET) framework, used by developers to build and manage websites and intranets.$q$, $q$It was created by Niels Hartvig, who began development around 2000 and released Umbraco as open source in 2004, with the CMS becoming fully open source at version 2.0 in 2005. Since version 4.5 the codebase has been licensed under MIT.$q$, $q$The company behind Umbraco, Umbraco A/S, is headquartered in Odense, Denmark, with a U.S. headquarters opened in Charlotte, North Carolina in 2020, and more than 500,000 live websites currently run on Umbraco.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c1977ce3-5ae1-4d22-8fba-55e0bd8412db', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Umbraco provides a flexible content editing interface built around customizable document types, allowing developers to define exactly what content editors can create and edit.$q$, $q$It supports a headless/hybrid delivery model through its Content Delivery API, multi-site and multi-language content management, member and role-based access for building portals or gated content, and a large marketplace of community and commercial packages that extend functionality.$q$, $q$As a .NET application, Umbraco integrates naturally with Microsoft Azure hosting, Visual Studio tooling, and existing enterprise .NET codebases, which is a key reason it is favored by organizations already using the Microsoft stack.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c1977ce3-5ae1-4d22-8fba-55e0bd8412db', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$The core Umbraco CMS is free and open source under the MIT license, with no cost to download, self-host, or modify the code.$q$, $q$Umbraco Cloud, the company's managed hosting service, is tiered at roughly 55 dollars per month for Starter, 330 dollars per month for Standard, 900 dollars per month for Professional, and custom Enterprise pricing for dedicated infrastructure and SLAs.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cfe083dd-da65-4b67-83be-298a4c15c75c', $q$One-click app store$q$, $q$Install more than 300 self-hosted applications with a single click, no Docker or command-line knowledge required.$q$, 0);
