INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cfe083dd-da65-4b67-83be-298a4c15c75c', $q$Home Assistant support$q$, $q$Self-host smart home automation and device control.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cfe083dd-da65-4b67-83be-298a4c15c75c', $q$Remote access$q$, $q$Securely access self-hosted apps and files from outside the home network.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cfe083dd-da65-4b67-83be-298a4c15c75c', $q$Umbrel Home hardware$q$, $q$Optional plug-and-play server appliance for users who do not want to build their own device.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('cfe083dd-da65-4b67-83be-298a4c15c75c', $q$Free and open-source software with no subscription cost$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('cfe083dd-da65-4b67-83be-298a4c15c75c', $q$Very approachable for non-technical users compared to raw Docker or Linux server setups$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('cfe083dd-da65-4b67-83be-298a4c15c75c', $q$Large, growing app store covering storage, media, smart home, and crypto use cases$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('cfe083dd-da65-4b67-83be-298a4c15c75c', $q$Keeps personal data under the user's own control instead of third-party cloud providers$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('cfe083dd-da65-4b67-83be-298a4c15c75c', $q$Umbrel Home offers a turnkey hardware option for those who do not want to self-assemble$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('cfe083dd-da65-4b67-83be-298a4c15c75c', $q$Requires owning and maintaining physical hardware$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('cfe083dd-da65-4b67-83be-298a4c15c75c', $q$Umbrel Home hardware cost (699 dollars) is a meaningful upfront investment$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('cfe083dd-da65-4b67-83be-298a4c15c75c', $q$Reliability and uptime depend on the user's home network and power stability$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('cfe083dd-da65-4b67-83be-298a4c15c75c', $q$Smaller company with limited formal enterprise support compared to commercial cloud providers$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('cfe083dd-da65-4b67-83be-298a4c15c75c', $q$Some advanced apps still require basic technical troubleshooting$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cfe083dd-da65-4b67-83be-298a4c15c75c', $q$Is Umbrel free?$q$, $q$Yes, umbrelOS and its app store are free and open source; users only pay for their own hardware or the optional Umbrel Home appliance.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cfe083dd-da65-4b67-83be-298a4c15c75c', $q$What is Umbrel used for?$q$, $q$Umbrel is used to self-host apps like file storage, media servers, smart home automation, and a Bitcoin node on a personal home server.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cfe083dd-da65-4b67-83be-298a4c15c75c', $q$Who founded Umbrel?$q$, $q$Umbrel was founded in 2020 by Mayank Chhabra and Luke Childs.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cfe083dd-da65-4b67-83be-298a4c15c75c', $q$What hardware does Umbrel run on?$q$, $q$umbrelOS commonly runs on a Raspberry Pi 4 or 5, an old PC repurposed as a server, or the company's own Umbrel Home appliance.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cfe083dd-da65-4b67-83be-298a4c15c75c', $q$What is Umbrel Home?$q$, $q$Umbrel Home is a pre-built, plug-and-play server appliance sold by Umbrel for 699 dollars, designed for users who want ready-made hardware.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cfe083dd-da65-4b67-83be-298a4c15c75c', $q$How many apps are in the Umbrel App Store?$q$, $q$The Umbrel App Store offers one-click installation for more than 300 self-hosted applications.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cfe083dd-da65-4b67-83be-298a4c15c75c', $q$Does Umbrel require technical skills to set up?$q$, $q$Umbrel is designed to be approachable for non-technical users, though some familiarity with home networking is helpful.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cfe083dd-da65-4b67-83be-298a4c15c75c', $q$Is Umbrel the same as Umbraco?$q$, $q$No, Umbrel is a self-hosted personal server operating system, while Umbraco is an unrelated open-source .NET content management system.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('cfe083dd-da65-4b67-83be-298a4c15c75c', $q$Personal cloud storage$q$, $q$Users run Nextcloud on Umbrel to replace paid cloud storage subscriptions with self-hosted file sync.$q$, $q$Privacy-conscious individuals and home users$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('cfe083dd-da65-4b67-83be-298a4c15c75c', $q$Home media server$q$, $q$Households run Plex or Jellyfin on Umbrel to stream their own media library instead of relying on streaming subscriptions.$q$, $q$Home media enthusiasts$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('cfe083dd-da65-4b67-83be-298a4c15c75c', $q$Running a Bitcoin node$q$, $q$Cryptocurrency users run a full Bitcoin and Lightning node from the Umbrel app store for network participation and privacy.$q$, $q$Bitcoin and cryptocurrency enthusiasts$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('cfe083dd-da65-4b67-83be-298a4c15c75c', $q$umbrelOS$q$, $q$Free$q$, $q$n/a$q$, NULL, $q$["Open-source server operating system","One-click app store access","Runs on user-supplied hardware"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('cfe083dd-da65-4b67-83be-298a4c15c75c', $q$Umbrel Home$q$, $q$$699$q$, $q$one-time$q$, NULL, $q$["Pre-built plug-and-play server hardware","Quad-core Intel CPU, 16GB RAM, 2TB NVMe SSD","Low power consumption"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('cfe083dd-da65-4b67-83be-298a4c15c75c', $q$overview$q$, $q$What Is Umbrel$q$, 2, ARRAY[$q$Umbrel is a free, open-source operating system called umbrelOS that transforms a Raspberry Pi, spare PC, or dedicated device into a personal home server, giving users a simple app store to self-host their own cloud services.$q$, $q$It was founded in 2020 by Mayank Chhabra and Luke Childs, aiming to make self-hosting accessible to people without deep technical expertise by wrapping Docker containers in a friendly, one-click interface.$q$, $q$In 2023, Umbrel began selling Umbrel Home, a plug-and-play hardware appliance for people who want a ready-made server instead of assembling their own.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('cfe083dd-da65-4b67-83be-298a4c15c75c', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The Umbrel App Store offers one-click installation of more than 300 self-hosted applications, including Nextcloud for file sync and storage, Plex and Jellyfin for media streaming, Home Assistant for smart home automation, and a Bitcoin and Lightning node.$q$, $q$umbrelOS provides a clean, mobile-responsive dashboard for managing installed apps, storage, backups, and remote access without needing command-line or Docker expertise.$q$, $q$Because it runs on the user's own hardware, all data stays local, giving people an alternative to depending on third-party cloud services like Google Drive, Dropbox, or streaming subscriptions.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('cfe083dd-da65-4b67-83be-298a4c15c75c', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$umbrelOS itself is completely free and open source, with no subscription fee; users only need compatible hardware, most commonly a Raspberry Pi 4 or 5, an old PC, or a home server.$q$, $q$For users who want ready-made hardware, Umbrel sells Umbrel Home, a pre-built plug-and-play server appliance priced at 699 dollars, with financing options available through installment plans.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('cfe083dd-da65-4b67-83be-298a4c15c75c', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
