INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a3310151-7d88-4c23-b959-1faaa5132f8d', $q$What is Unbounce used for?$q$, $q$Unbounce is used to build, test, and publish landing pages, popups, and sticky bars for marketing campaigns without coding.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a3310151-7d88-4c23-b959-1faaa5132f8d', $q$How much does Unbounce cost?$q$, $q$Unbounce starts at 99 dollars per month for the Build plan, with Experiment at 149 dollars per month and Optimize at 249 dollars per month.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a3310151-7d88-4c23-b959-1faaa5132f8d', $q$Who founded Unbounce?$q$, $q$Unbounce was founded in 2009 in Vancouver, Canada, by Rick Perreault, Carl Schmidt, Oli Gardner, and Jason Murphy.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a3310151-7d88-4c23-b959-1faaa5132f8d', $q$What is Unbounce Smart Traffic?$q$, $q$Smart Traffic is an AI feature that automatically routes visitors to the landing page variant statistically most likely to convert them.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a3310151-7d88-4c23-b959-1faaa5132f8d', $q$Is there a free trial for Unbounce?$q$, $q$Yes, Unbounce offers a 14-day free trial on all its pricing plans.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a3310151-7d88-4c23-b959-1faaa5132f8d', $q$Who owns Unbounce?$q$, $q$Private equity firm Thoma Bravo acquired a majority stake in Unbounce in 2021.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a3310151-7d88-4c23-b959-1faaa5132f8d', $q$Does Unbounce support A/B testing?$q$, $q$Yes, A/B testing is built into the Experiment and Optimize plans, allowing marketers to test multiple page variants.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a3310151-7d88-4c23-b959-1faaa5132f8d', $q$What are the main Unbounce alternatives?$q$, $q$Common alternatives include Instapage, Leadpages, and landing page tools built into platforms like HubSpot.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a3310151-7d88-4c23-b959-1faaa5132f8d', $q$PPC campaign landing pages$q$, $q$Marketers build dedicated landing pages matched to specific ad campaigns using dynamic text replacement to boost quality scores and conversions.$q$, $q$PPC and performance marketers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a3310151-7d88-4c23-b959-1faaa5132f8d', $q$Lead generation campaigns$q$, $q$Agencies and marketing teams build gated content and lead-capture pages tied to email marketing and CRM systems.$q$, $q$Marketing agencies and demand generation teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a3310151-7d88-4c23-b959-1faaa5132f8d', $q$Conversion rate optimization programs$q$, $q$Growth teams run continuous A/B tests and use Smart Traffic to systematically improve landing page conversion rates.$q$, $q$Growth marketers and CRO specialists$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('a3310151-7d88-4c23-b959-1faaa5132f8d', $q$Build$q$, $q$$99/month (~$64/month billed annually)$q$, $q$monthly or annual$q$, NULL, $q$["Unlimited landing pages, popups, and sticky bars","Up to 20,000 monthly visitors","Drag-and-drop builder"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('a3310151-7d88-4c23-b959-1faaa5132f8d', $q$Experiment$q$, $q$$149/month (~$96/month billed annually)$q$, $q$monthly or annual$q$, NULL, $q$["Everything in Build","Unlimited A/B testing and variants"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('a3310151-7d88-4c23-b959-1faaa5132f8d', $q$Optimize$q$, $q$$249/month (~$161/month billed annually)$q$, $q$monthly or annual$q$, NULL, $q$["Everything in Experiment","Smart Traffic AI optimization","Advanced location and cookie targeting","Up to 50,000 monthly visitors"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a3310151-7d88-4c23-b959-1faaa5132f8d', $q$overview$q$, $q$What Is Unbounce$q$, 2, ARRAY[$q$Unbounce is a no-code landing page builder and conversion optimization platform that lets marketers create, publish, and test landing pages, popups, and sticky bars without relying on developers.$q$, $q$It was founded in 2009 in Vancouver, Canada, by Rick Perreault, Carl Schmidt, Oli Gardner, and Jason Murphy, making it one of the earliest dedicated landing page platforms in the marketing technology space.$q$, $q$In 2021, private equity firm Thoma Bravo acquired a majority stake in Unbounce, and the company has continued to operate and expand its product line under that ownership, including leadership changes such as CEO Felicia Bochicchio in 2023.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a3310151-7d88-4c23-b959-1faaa5132f8d', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The core builder uses a drag-and-drop editor for landing pages, popups, and sticky bars, with a library of conversion-focused templates spanning industries and campaign types.$q$, $q$Unbounce's built-in A/B testing lets marketers run multiple page variants and measure conversion performance, while its Smart Traffic feature uses AI to automatically send visitors to the variant most likely to convert them based on attributes like device, location, and traffic source.$q$, $q$The platform also supports dynamic text replacement for PPC campaigns, integrations with major marketing and CRM tools, and advanced targeting options including location-based and cookie-based targeting on higher tiers.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a3310151-7d88-4c23-b959-1faaa5132f8d', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Unbounce is priced across three main tiers: Build at 99 dollars per month for unlimited landing pages, popups, and sticky bars with up to 20,000 monthly visitors; Experiment at 149 dollars per month adding unlimited A/B testing; and Optimize at 249 dollars per month adding the AI-driven Smart Traffic feature and advanced targeting.$q$, $q$Annual billing lowers the effective monthly rate on each tier, and all plans include a 14-day free trial before requiring payment.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('a3310151-7d88-4c23-b959-1faaa5132f8d', '87a92d11-ee13-4164-9910-61410254388a') ON CONFLICT DO NOTHING;
