-- ── Ulysses ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Ulysses is a Mac, iPad, and iPhone writing app built for long-form authors, offering a distraction-free Markdown editor with library organization and export to multiple formats.$q$, short_description),
  pricing_model = COALESCE($q$subscription$q$, pricing_model),
  starting_price = COALESCE($q$$5.99/month$q$, starting_price),
  founded_year = COALESCE(2003, founded_year),
  company_size = COALESCE($q$1-10 employees$q$, company_size),
  headquarters = COALESCE($q$Germany$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$German$q$, $q$French$q$, $q$Spanish$q$, $q$Chinese$q$, $q$Japanese$q$]::text[],
  seo_title = COALESCE($q$Ulysses Review 2026: Mac and iOS Writing App Pricing$q$, seo_title),
  seo_meta_description = COALESCE($q$Ulysses is a distraction-free Markdown writing app for Mac, iPad, and iPhone. See its features, subscription pricing, and who it is built for.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Ulysses is a long-form writing application built exclusively for Apple platforms, macOS, iPadOS, and iOS, developed by The Soulmen, a small German independent software studio. The app has been in development since 2003 and is aimed at authors, journalists, bloggers, and academics who write long documents such as novels, articles, and theses. Ulysses organizes writing into a searchable library of sheets and groups rather than loose files, uses a lightweight Markup syntax (a Markdown variant) for formatting so writers can stay in a distraction-free plain-text environment, and exports finished work to formats including PDF, ePub, Word (.docx), HTML, and direct publishing to WordPress and Medium. In August 2017, Ulysses moved from a one-time purchase model to a subscription, a widely discussed shift covered by outlets like 9to5Mac, TidBITS, and Cult of Mac at the time. As of 2026, pricing is 5.99 dollars per month or 49.99 dollars per year, with a discounted 34.99 dollar annual education rate for verified students and educators, and legacy customers who purchased before the subscription switch retain a grandfathered discounted renewal rate around 30 dollars per year. A single subscription covers Mac, iPad, and iPhone, and Apple Family Sharing extends access to up to five family members. Ulysses has no Windows, Android, or web version, making it a Mac-ecosystem-only tool, which distinguishes it from cross-platform competitors like Scrivener, iA Writer, and Notion. Its appeal centers on a polished writing-focused interface, reliable iCloud/Mac sync, and a workflow purpose-built for drafting and exporting long manuscripts rather than general note-taking or collaboration.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '96f26d26-8a1d-438a-a8a3-ab3602c704c2';

