-- ── umami ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$umami is an open-source, privacy-focused web analytics platform that can be self-hosted for free or used as a hosted cloud service, positioned as a lightweight Google Analytics alternative.$q$, short_description),
  pricing_model = COALESCE($q$open-source$q$, pricing_model),
  starting_price = COALESCE($q$Free (self-hosted); Cloud from free, Pro plans available$q$, starting_price),
  founded_year = COALESCE(2020, founded_year),
  company_size = COALESCE($q$1-10 employees$q$, company_size),
  headquarters = COALESCE($q$United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$umami Review 2026: Open-Source Privacy Analytics Pricing$q$, seo_title),
  seo_meta_description = COALESCE($q$umami is an open-source, privacy-first web analytics tool. Compare self-hosted vs Umami Cloud pricing, features, and how it works as a GA alternative.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$umami is an open-source, privacy-focused website analytics platform created by Mike Cao, who built the first version in late 2020 after wanting a faster, simpler, cookie-free alternative to Google Analytics for his own personal websites and open-sourced it immediately. Umami Software, Inc., co-founded with Brian Cao and Francis Cao, was later established around the project and raised 1.5 million dollars in a pre-seed funding round led by Race Capital in July 2022 to grow the open-source platform and its hosted cloud offering. The codebase is MIT-licensed and free to self-host indefinitely, tracking pageviews, visitors, referrers, UTM campaigns, custom events, and goals without using cookies, which allows it to operate in many jurisdictions without a cookie consent banner while remaining GDPR- and CCPA-friendly. For teams that do not want to manage their own server and database, Umami Cloud offers a hosted version: a free Hobby tier supporting roughly 100,000 events per month across a limited number of sites, and a paid Pro tier priced around 20 dollars per month for higher event volumes (roughly 1 million events per month), more sites, longer data retention, and email reports, with custom Enterprise pricing available on request. umami's dashboard emphasizes simplicity: a single-page overview of traffic, top pages, referrers, devices, and countries, an approach that contrasts with the deeper but more complex reporting in Google Analytics 4 or paid competitors like Plausible, Fathom, and Simple Analytics. Because it is open source, umami can also be self-hosted on infrastructure like Vercel, Railway, Docker, or a VPS, giving technical teams full data ownership at no licensing cost, which is its core differentiator from closed-source privacy analytics competitors.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '2dc59fc4-cba5-4e5f-9d82-31860bce5d72';

