-- ── Umbraco ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Umbraco is a free, open-source .NET content management system used to build and manage websites, with an optional managed Umbraco Cloud hosting service for teams.$q$, short_description),
  pricing_model = COALESCE($q$open-source$q$, pricing_model),
  starting_price = COALESCE($q$Free (CMS); Umbraco Cloud from $55/month$q$, starting_price),
  founded_year = COALESCE(2000, founded_year),
  company_size = COALESCE($q$201-500 employees$q$, company_size),
  headquarters = COALESCE($q$Odense, Denmark$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$Danish$q$, $q$German$q$, $q$French$q$, $q$Spanish$q$, $q$Dutch$q$]::text[],
  seo_title = COALESCE($q$Umbraco Review 2026: Open-Source .NET CMS Pricing$q$, seo_title),
  seo_meta_description = COALESCE($q$Umbraco is a free, open-source .NET CMS. See its history, features, MIT license, and Umbraco Cloud pricing plans for 2026.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Umbraco is an open-source content management system built on the Microsoft .NET (ASP.NET) platform, originally developed by Niels Hartvig starting around 2000 and released publicly as open-source software in 2004, becoming fully open under Umbraco 2.0 in February 2005; the codebase has been available under an MIT license since version 4.5. The company behind it, Umbraco A/S, is headquartered in Odense, Denmark, and opened a United States headquarters in Charlotte, North Carolina in 2020 to support its growing American customer base; the company reports several hundred employees globally. Umbraco is used to power more than 500,000 live websites and has a community of over 220,000 active members, making it one of the most widely deployed .NET-based open-source CMS platforms. The core Umbraco CMS is free to download, self-host, and modify under its MIT license, while the company generates revenue primarily through Umbraco Cloud, a managed hosting and DevOps service that adds automated deployments, backups, and scaling on top of the open-source CMS. Umbraco Cloud is tiered into a Starter plan (around 55 dollars per month, aimed at low-traffic, low-complexity sites on shared infrastructure), a Standard plan (around 330 dollars per month), a Professional plan (around 900 dollars per month), and a custom-quoted Enterprise plan with dedicated resources and SLAs. Umbraco competes with other .NET and open-source CMS platforms such as Sitecore, Kentico, and Optimizely, as well as broader CMS alternatives like WordPress, and is generally chosen by organizations already invested in the Microsoft development stack that want an open-source, developer-friendly content platform rather than a proprietary enterprise CMS license.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'c1977ce3-5ae1-4d22-8fba-55e0bd8412db';

