-- ── Umbrel ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Umbrel is a free, open-source personal server operating system (umbrelOS) with a one-click app store, letting anyone self-host apps like Nextcloud, Plex, and a Bitcoin node on a home server.$q$, short_description),
  pricing_model = COALESCE($q$open-source$q$, pricing_model),
  starting_price = COALESCE($q$Free (software); Umbrel Home hardware from $699$q$, starting_price),
  founded_year = COALESCE(2020, founded_year),
  company_size = COALESCE($q$1-10 employees$q$, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Umbrel Review 2026: Self-Hosted Home Server OS Pricing$q$, seo_title),
  seo_meta_description = COALESCE($q$Umbrel is a free, open-source home server OS with a one-click app store. See umbrelOS features, self-hosted apps, and Umbrel Home hardware pricing.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Umbrel is an open-source personal cloud operating system, umbrelOS, that turns a Raspberry Pi, old PC, or dedicated device into a self-hosted home server with a one-click app store. It was founded in 2020 by Mayank Chhabra and Luke Childs, who set out to make self-hosting accessible to non-technical users by wrapping Docker-based apps in a simple, mobile-friendly interface. The umbrelOS software and its underlying app store infrastructure are free and open source, with no subscription fees; users install it on their own hardware (commonly a Raspberry Pi 4/5) at no software cost. The Umbrel App Store offers one-click installation for more than 300 self-hosted applications, including Nextcloud for file storage, Plex and Jellyfin for media streaming, Home Assistant for smart home control, a Bitcoin full node and Lightning node, password managers, and various developer tools, positioning Umbrel as an alternative to relying on third-party cloud services like Google Drive, Dropbox, or Spotify for people who want to own and control their own data. In 2023, the company began selling Umbrel Home, a plug-and-play pre-built server appliance priced at 699 dollars, featuring a quad-core Intel CPU, 16GB of RAM, a 2TB NVMe SSD, and low power draw (around 10 watts), aimed at users who want turnkey hardware without assembling their own Raspberry Pi setup. Umbrel has raised early-stage venture funding and reports modest annual recurring revenue in the low millions as of 2024-2025 estimates from third-party data providers, reflecting its niche but growing presence in the self-hosting and home server community alongside comparable projects like CasaOS, TrueNAS, and Unraid.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
