-- ── Unbounce ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Unbounce is a landing page builder and conversion optimization platform that lets marketers create, test, and publish landing pages, popups, and sticky bars without coding.$q$, short_description),
  pricing_model = COALESCE($q$subscription$q$, pricing_model),
  starting_price = COALESCE($q$$99/month$q$, starting_price),
  founded_year = COALESCE(2009, founded_year),
  company_size = COALESCE($q$201-500 employees$q$, company_size),
  headquarters = COALESCE($q$Vancouver, British Columbia, Canada$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Unbounce Review 2026: Landing Page Builder Pricing$q$, seo_title),
  seo_meta_description = COALESCE($q$Unbounce is a no-code landing page builder with A/B testing and AI optimization. See its 2026 pricing plans, features, and who it is built for.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Unbounce is a landing page building and conversion optimization platform founded in 2009 in Vancouver, Canada, by Rick Perreault, Carl Schmidt, Oli Gardner, and Jason Murphy, created to let marketers build and test landing pages without needing developers. The company is headquartered in Vancouver and grew into one of the earliest dedicated landing page tools in the martech category; in 2021, private equity firm Thoma Bravo acquired a majority stake in Unbounce, valuing the company at an estimated enterprise value exceeding 800 million dollars, and the company has continued operating under that ownership with leadership changes including CEO Felicia Bochicchio taking over in 2023. Unbounce's core product is a drag-and-drop, no-code builder for landing pages, popups, and sticky bars, paired with built-in A/B testing and its Smart Traffic feature, an AI-driven tool that automatically routes visitors to the page variant statistically most likely to convert them, learning from real-time visitor data rather than waiting for a test to reach full statistical significance. As of 2026, Unbounce is priced across three core tiers: Build at 99 dollars per month (around 64 dollars per month billed annually) for unlimited landing pages and popups up to 20,000 monthly visitors; Experiment at 149 dollars per month for unlimited A/B testing and variants; and Optimize at 249 dollars per month, which adds Smart Traffic and advanced targeting like location and cookie-based targeting, supporting up to 50,000 monthly unique visitors. All plans include a 14-day free trial. Unbounce competes with Instapage, Leadpages, and HubSpot's landing page tools, and differentiates itself primarily through its emphasis on conversion-rate optimization and AI-assisted traffic routing rather than being purely a page-design tool.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'a3310151-7d88-4c23-b959-1faaa5132f8d';

